const GetOutageOverlapForInvoice = `-- name: GetOutageOverlapForInvoice :one
SELECT COALESCE(
    SUM(
        LEAST(COALESCE(o.ended_at, NOW()), $1::timestamptz)
        - GREATEST(o.started_at, $2::timestamptz)
    ),
    '0 seconds'::interval
) AS total_outage_overlap
FROM btc_outage_log o
WHERE o.network    = $3
  AND o.started_at < $1::timestamptz
  AND COALESCE(o.ended_at, NOW()) > $2::timestamptz
`

type GetOutageOverlapForInvoiceParams struct {
	ExpiresAt        pgtype.Timestamptz `db:"expires_at" json:"expires_at"`
	InvoiceCreatedAt pgtype.Timestamptz `db:"invoice_created_at" json:"invoice_created_at"`
	Network          string             `db:"network" json:"network"`
}

// Expiry compensation formula: total outage duration that overlapped with
// an invoice's life. The expiry cleanup job adds this to expires_at before
// deciding whether to mark the invoice expired.
//
// Overlap = LEAST(outage_end, invoice_expires_at)
//   - GREATEST(outage_start, invoice_created_at)
//
// Summed across all outages that touch the invoice window.
// Returns INTERVAL '0' when no overlapping outages exist.
// Index: idx_outage_range ON btc_outage_log(network, started_at, ended_at)
func (q *Queries) GetOutageOverlapForInvoice(ctx context.Context, arg GetOutageOverlapForInvoiceParams) (interface{}, error) {
	row := q.db.QueryRow(ctx, GetOutageOverlapForInvoice, arg.ExpiresAt, arg.InvoiceCreatedAt, arg.Network)
	var total_outage_overlap interface{}
	err := row.Scan(&total_outage_overlap)
	return total_outage_overlap, err
}

