const LoadActiveMonitoringByNetwork = `-- name: LoadActiveMonitoringByNetwork :many
SELECT
    iam.invoice_id,
    iam.address,
    iam.network,
    iam.monitor_until
FROM invoice_address_monitoring iam
WHERE iam.network = $1
  AND iam.status  = 'active'
ORDER BY iam.invoice_id
`

type LoadActiveMonitoringByNetworkRow struct {
	InvoiceID    pgtype.UUID        `db:"invoice_id" json:"invoice_id"`
	Address      string             `db:"address" json:"address"`
	Network      string             `db:"network" json:"network"`
	MonitorUntil pgtype.Timestamptz `db:"monitor_until" json:"monitor_until"`
}

// ZMQ startup / reconnect: rebuild the in-memory watch set for a network.
// Called on every startup and after every reconnect so the subscriber
// knows which addresses to watch before it starts dispatching events.
// Index: idx_iam_reload ON invoice_address_monitoring(network, invoice_id)
//
//	WHERE status = 'active'
func (q *Queries) LoadActiveMonitoringByNetwork(ctx context.Context, network string) ([]LoadActiveMonitoringByNetworkRow, error) {
	rows, err := q.db.Query(ctx, LoadActiveMonitoringByNetwork, network)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []LoadActiveMonitoringByNetworkRow{}
	for rows.Next() {
		var i LoadActiveMonitoringByNetworkRow
		if err := rows.Scan(
			&i.InvoiceID,
			&i.Address,
			&i.Network,
			&i.MonitorUntil,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const MarkInvoiceSweepCompleted = `-- name: MarkInvoiceSweepCompleted :execrows
UPDATE invoices
SET
    sweep_completed = TRUE,
    updated_at      = NOW()
WHERE id              = $1::uuid
  AND sweep_completed = FALSE
`

// Set sweep_completed = TRUE atomically with the constructing → broadcast
// payout transition. The reorg rollback logic pivots on this field:
//
//	TRUE  → reorg_admin_required (sweep may already be broadcast)
//	FALSE → roll back to detected (safe to re-settle)
//
// Called in the same transaction as SetPayoutBroadcast.
// Caller MUST assert RowsAffected() == 1.
func (q *Queries) MarkInvoiceSweepCompleted(ctx context.Context, invoiceID pgtype.UUID) (int64, error) {
	result, err := q.db.Exec(ctx, MarkInvoiceSweepCompleted, invoiceID)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

