const RetireExpiredMonitoringRecords = `-- name: RetireExpiredMonitoringRecords :many
UPDATE invoice_address_monitoring
SET
    status     = 'retired',
    updated_at = NOW()
WHERE status        = 'active'
  AND monitor_until IS NOT NULL
  AND monitor_until < NOW()
RETURNING invoice_id
`

// Expiry cleanup job: retire active monitoring records whose window has elapsed.
// Retired rows are NEVER deleted — they form the permanent monitoring audit trail.
// The partial index on status = 'active' keeps all queries fast regardless of
// how many retired rows accumulate.
// Index: idx_iam_expiry_cleanup ON invoice_address_monitoring(monitor_until)
//
//	WHERE status = 'active' AND monitor_until IS NOT NULL
func (q *Queries) RetireExpiredMonitoringRecords(ctx context.Context) ([]pgtype.UUID, error) {
	rows, err := q.db.Query(ctx, RetireExpiredMonitoringRecords)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []pgtype.UUID{}
	for rows.Next() {
		var invoice_id pgtype.UUID
		if err := rows.Scan(&invoice_id); err != nil {
			return nil, err
		}
		items = append(items, invoice_id)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

